mapper.select:
SELECT

FROM TEST_EVIDENCE TE
INNER JOIN PROJECT P ON TE.PROJECT_ID = P.PROJECT_ID
INNER JOIN ISSUE I ON TE.ISSUE_ID = I.ISSUE_ID
INNER JOIN APP_USER U ON TE.TESTER_ID = U.USER_ID


        AND TE.PROJECT_ID = #{projectId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}


        AND TE.ISSUE_ID = #{issueId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}


        AND TE.RESULT_STATUS = #{resultStatus}


        AND CAST(TE.TESTED_AT AS DATE) >= #{testedAtFrom}


        AND CAST(TE.TESTED_AT AS DATE) <= #{testedAtTo}


        AND (
            TE.TEST_NAME ILIKE CONCAT('%', #{keyword}, '%')
            OR TE.TEST_TARGET ILIKE CONCAT('%', #{keyword}, '%')
            OR I.ISSUE_KEY ILIKE CONCAT('%', #{keyword}, '%')
            OR I.TITLE ILIKE CONCAT('%', #{keyword}, '%')
        )


ORDER BY TE.TESTED_AT DESC, TE.CREATED_AT DESC
